**Module 2**: Delete records with status 'Inactive' and log the changes  
```sql
DELIMITER $$

CREATE PROCEDURE delete_inactive_users()
BEGIN
    DECLARE done INT DEFAULT 0;
    DECLARE user_id INT;
    DECLARE cur CURSOR FOR SELECT user_id FROM users WHERE status = 'Inactive';
    DECLARE CONTINUE HANDLER OUTSIDE BEGIN SET done = 1; END;

    START TRANSACTION;

    OPEN cur;
    FETCH cur INTO user_id;

    WHILE done = 0 DO
        IF EXISTS (SELECT 1 FROM users WHERE user_id = user_id AND status = 'Inactive') THEN
            UPDATE users SET status = 'Active' WHERE user_id = user_id;
            INSERT INTO status_log (user_id, status, modification_date) VALUES (user_id, 'Active', NOW());
        END IF;
        FETCH cur INTO user_id;
    END WHILE;

    COMMIT;
END $$

DELIMITER ;
```

